/**
 * @summary Convert amount from one currency to another
 */
export const getConvertCurrencyUrl = (params: ConvertCurrencyParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/currency/convert?${stringifiedParams}`
    : `/api/currency/convert`;
};

export const convertCurrency = async (
  params: ConvertCurrencyParams,
  options?: RequestInit,
): Promise<CurrencyConversionResponse> => {
  return customFetch<CurrencyConversionResponse>(
    getConvertCurrencyUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getConvertCurrencyQueryKey = (params?: ConvertCurrencyParams) => {
  return [`/api/currency/convert`, ...(params ? [params] : [])] as const;
};

export const getConvertCurrencyQueryOptions = <
  TData = Awaited<ReturnType<typeof convertCurrency>>,
  TError = ErrorType<unknown>,
>(
  params: ConvertCurrencyParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof convertCurrency>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getConvertCurrencyQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof convertCurrency>>> = ({
    signal,
  }) => convertCurrency(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof convertCurrency>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

